/* ── DOM ── */
var fab=document.createElement("button");
fab.id="mc-fab";fab.className="pulse";fab.innerHTML="\u26bd";
fab.title="Mascote Copa 2026";
document.body.appendChild(fab);

var panel=document.createElement("div");
panel.id="mc-panel";
document.body.appendChild(panel);

fab.addEventListener("click",function(){
  panelOpen=!panelOpen;
  if(panelOpen){fab.classList.remove("pulse");panel.classList.add("open");render();}
  else{panel.classList.remove("open");}
});

/* ── Render ── */
function render(){
  if(!country){renderSelect();return;}
  renderMain();
}

function renderSelect(){
  panel.innerHTML='\
<div class="mc-head"><span class="mc-title">\u26bd Copa 2026</span><button class="mc-close" onclick="document.getElementById(\'mc-panel\').classList.remove(\'open\')">\u2715</button></div>\
<div class="mc-body"><div class="mc-select">\
<h2>Selecione sua Seleção!</h2>\
<p>Aqui você torce e estuda ao mesmo tempo! \ud83c\udfc6\ud83d\udcda</p>\
<div class="mc-opts">\
<div class="mc-opt" data-c="br"><img src="'+BR_IMG+'"><div class="mc-opt-label">\ud83c\udde7\ud83c\uddf7 BRASIL</div><div class="mc-opt-grupo">1\u00ba Grupo C \u2713</div></div>\
<div class="mc-opt" data-c="py"><img src="'+PY_IMG+'"><div class="mc-opt-label">\ud83c\uddf5\ud83c\uddfe PARAGUAY</div><div class="mc-opt-grupo">3\u00ba Grupo D \u2713</div></div>\
</div></div></div>';
  panel.querySelectorAll(".mc-opt").forEach(function(el){
    el.addEventListener("click",function(){country=el.getAttribute("data-c");kicks=0;tab="game";render();});
  });
}

function renderMain(){
  var img=country==="br"?BR_IMG:PY_IMG;
  var flag=country==="br"?"\ud83c\udde7\ud83c\uddf7":"\ud83c\uddf5\ud83c\uddfe";
  var name=country==="br"?"BRASIL":"PARAGUAY";
  var grupo=country==="br"?"Grupo C \u2022 1\u00ba \u2713":"Grupo D \u2022 3\u00ba \u2713";
  
  panel.innerHTML='\
<div class="mc-head">\
  <div style="display:flex;align-items:center;gap:8px"><button class="mc-back" id="mcBack">\u2190</button><span class="mc-title">'+flag+' '+name+' \u2022 '+grupo+'</span></div>\
  <button class="mc-close" id="mcClose">\u2715</button>\
</div>\
<div class="mc-tabs"><button class="mc-tab'+(tab==="game"?" active":"")+'" data-t="game">\u26bd Embaixadinha</button><button class="mc-tab'+(tab==="calendar"?" active":"")+'" data-t="calendar">\ud83d\udcc5 Jogos</button></div>\
<div class="mc-body" id="mcBody"></div>';

  document.getElementById("mcBack").addEventListener("click",function(){country=null;render();});
  document.getElementById("mcClose").addEventListener("click",function(){panel.classList.remove("open");panelOpen=false;});
  panel.querySelectorAll(".mc-tab").forEach(function(t){
    t.addEventListener("click",function(){tab=t.getAttribute("data-t");render();});
  });

  var body=document.getElementById("mcBody");
  if(tab==="calendar") renderCalendar(body);
  else renderGame(body);
}

function renderCalendar(el){
  var jogos=country==="br"?JOGOS_BR:JOGOS_PY;
  var tz=country==="br"?"\ud83d\udd50 Horário de MS (Campo Grande)":"\ud83d\udd50 Horario de Paraguay (Asunción)";
  var html='<div class="mc-tz">'+tz+'</div>';
  jogos.forEach(function(j){
    var cls="mc-match"+(j.next?" next":"")+(j.done?" done":"");
    var tagTxt=j.next?"PR\u00d3XIMO":j.done?"ENCERRADO":"";
    html+='<div class="'+cls+'">';
    if(tagTxt) html+='<div class="mc-match-tag">'+tagTxt+'</div>';
    html+='<div class="mc-match-row1"><span>'+j.date+'</span><span class="mc-time">'+j.time+'</span></div>';
    html+='<div class="mc-match-teams">'+j.f1+' '+j.t1+' '+(j.score?'<span class="mc-score">'+j.score+'</span>':'<span class="mc-vs">vs</span>')+' '+j.t2+' '+j.f2+'</div>';
    html+='<div class="mc-match-stad">'+j.stad+'</div></div>';
  });
  if(country==="br") html+='<div class="mc-mata"><b>\ud83c\udfc6 CLASSIFICADO! 1\u00ba do Grupo C</b><br>\u26bd 16 avos: 29/06 14h vs Jap\u00e3o (Houston)</div>';
  else html+='<div class="mc-mata"><b>\ud83c\udfc6 CLASSIFICADO! 3\u00ba do Grupo D</b><br>\u26bd 16 avos: 29/06 17h30 vs Alemanha (Boston)</div>';
  el.innerHTML=html;
}

function renderGame(el){
  var img=country==="br"?BR_IMG:PY_IMG;
  el.innerHTML='\
<div class="mc-game">\
<div class="mc-kicks" id="mcKicks">'+kicks+'</div>\
<div class="mc-kicks-label">embaixadinha'+(kicks!==1?"s":"")+'</div>\
<div class="mc-bubble" id="mcBubble"></div>\
<div class="mc-mascot-area" id="mcMascot"><canvas id="mcCanvas" width="360" height="360" style="position:absolute;top:-100px;left:50%;margin-left:-180px;width:360px;height:360px;pointer-events:none;z-index:5;"></canvas>\
<div id="mcImgWrap" class="mc-mascot-idle"><img src="'+img+'" class="mc-mascot-img"></div></div>\
<div class="mc-hint">Toque no jogador pra chutar! \u26bd \u2022 5x = MEGA GOL \ud83c\udfc6</div>\
</div>';
  document.getElementById("mcMascot").addEventListener("click",doKick);
}

/* ── Kick logic ── */
function doKick(){
  if(kicking)return;
  kicks++;kicking=true;
  var mega=kicks%5===0;
  var frases=country==="br"?FRASES_BR:FRASES_PY;
  var frase=mega?(country==="br"?"GOOOL! \ud83c\udfc6\ud83d\udd25":"\u00a1GOOOL! \ud83c\udfc6\ud83d\udd25"):frases[Math.floor(Math.random()*frases.length)];
  
  // Update counter
  var kEl=document.getElementById("mcKicks");if(kEl)kEl.textContent=kicks;
  
  // Bubble
  var bub=document.getElementById("mcBubble");
  if(bub){bub.textContent=frase;bub.className="mc-bubble show"+(mega?" mega":"");}
  
  // Kick animation
  var wrap=document.getElementById("mcImgWrap");
  if(wrap){wrap.className="mc-mascot-kick";setTimeout(function(){if(wrap)wrap.className="mc-mascot-idle";},550);}
  
  // Ball explosion
  fireBall(mega);
  
  // Flash on mega
  if(mega){
    var flash=document.createElement("div");
    flash.style.cssText="position:fixed;inset:0;z-index:99999;pointer-events:none;background:radial-gradient(circle,rgba(255,215,0,0.3),transparent 70%);animation:mcFlash 0.5s ease-out forwards;";
    document.body.appendChild(flash);
    setTimeout(function(){flash.remove();},600);
    // Combo text
    var combo=document.createElement("div");
    combo.textContent=kicks+"x COMBO!";
    combo.style.cssText="position:fixed;top:35%;left:0;right:0;text-align:center;font-size:30px;font-weight:900;color:#ffd700;z-index:100000;pointer-events:none;text-shadow:0 0 24px rgba(255,215,0,0.5);animation:mcCombo 0.8s ease-out forwards;font-family:Poppins,sans-serif;";
    document.body.appendChild(combo);
    setTimeout(function(){combo.remove();},900);
  }
  
  setTimeout(function(){
    if(bub)bub.className="mc-bubble";
    kicking=false;
  },mega?2800:1800);
}

/* ── Canvas ball explosion ── */
function fireBall(mega){
  var cv=document.getElementById("mcCanvas");if(!cv)return;
  var ctx=cv.getContext("2d");var W=cv.width,H=cv.height;
  var bx=180,by=310,vx=(Math.random()-0.5)*2.5,vy=mega?-13:-9-Math.random()*2;
  var grav=0.18,spin=0,phase="fly",ef=0,parts=[];
  var cols=mega?["#ffd700","#ff3d00","#00e676","#40c4ff","#ff6ec7","#fff"]:["#ffd700","#fff","#ff9100","#69f0ae","#40c4ff"];
  var emos=["\u26bd","\ud83d\udd25","\u2b50","\ud83d\udcab","\u2728","\ud83c\udfc6","\ud83c\udf89","\ud83e\udd73"];
  function boom(x,y){
    var n=mega?50:28;
    for(var i=0;i<n;i++){var a=(Math.PI*2*i)/n+(Math.random()-0.5)*0.5;var sp=(mega?5:3)+Math.random()*5;var isE=Math.random()<0.35;
      parts.push({x:x,y:y,vx:Math.cos(a)*sp,vy:Math.sin(a)*sp-(mega?3:1.5),r:isE?0:2+Math.random()*4,col:cols[Math.floor(Math.random()*cols.length)],life:1,dec:0.012+Math.random()*0.013,emoji:isE?emos[Math.floor(Math.random()*emos.length)]:null,rot:0,rs:(Math.random()-0.5)*0.3,g:0.04+Math.random()*0.04});}
    parts.push({x:x,y:y,ring:true,rad:0,maxR:mega?140:70,life:1,dec:0.03,col:"#ffd700"});
    if(mega){parts.push({x:x,y:y,ring:true,rad:0,maxR:100,life:1,dec:0.02,col:"#ff3d00"});}
  }
  function drawBall(x,y,r){ctx.save();ctx.translate(x,y);ctx.rotate(spin);var g=ctx.createRadialGradient(-r*0.3,-r*0.3,r*0.1,0,0,r);g.addColorStop(0,"#fff");g.addColorStop(0.5,"#e0e0e0");g.addColorStop(1,"#888");ctx.beginPath();ctx.arc(0,0,r,0,Math.PI*2);ctx.fillStyle=g;ctx.fill();ctx.strokeStyle="#555";ctx.lineWidth=1.2;ctx.stroke();ctx.beginPath();for(var i=0;i<5;i++){var a=(Math.PI*2*i)/5-Math.PI/2;var px=Math.cos(a)*r*0.42;var py=Math.sin(a)*r*0.42;i===0?ctx.moveTo(px,py):ctx.lineTo(px,py);}ctx.closePath();ctx.fillStyle="rgba(50,50,50,0.22)";ctx.fill();ctx.restore();}
  var id;
  function loop(){
    ctx.clearRect(0,0,W,H);
    if(phase==="fly"){vy+=grav;bx+=vx;by+=vy;spin+=0.18;for(var t=1;t<=3;t++){ctx.globalAlpha=0.12/t;ctx.beginPath();ctx.arc(bx-vx*t*2.5,by-vy*t*2.5,(mega?12:9)*0.6/t,0,Math.PI*2);ctx.fillStyle="#ffd700";ctx.fill();}ctx.globalAlpha=1;drawBall(bx,by,mega?13:10);if(vy>0&&by<310-50){phase="explode";boom(bx,by);}}
    if(phase==="explode"){ef++;var alive=false;for(var i=0;i<parts.length;i++){var p=parts[i];if(p.life<=0)continue;alive=true;p.life-=p.dec;if(p.ring){p.rad+=(p.maxR-p.rad)*0.1;ctx.globalAlpha=p.life*0.4;ctx.beginPath();ctx.arc(p.x,p.y,p.rad,0,Math.PI*2);ctx.strokeStyle=p.col;ctx.lineWidth=mega?3:2;ctx.stroke();ctx.globalAlpha=1;}else{p.vx*=0.985;p.vy+=p.g;p.vy*=0.985;p.x+=p.vx;p.y+=p.vy;p.rot+=p.rs;ctx.globalAlpha=Math.max(0,p.life);if(p.emoji){ctx.save();ctx.translate(p.x,p.y);ctx.rotate(p.rot);ctx.font=(mega?18:14)+"px serif";ctx.textAlign="center";ctx.textBaseline="middle";ctx.fillText(p.emoji,0,0);ctx.restore();}else{ctx.beginPath();ctx.arc(p.x,p.y,p.r*p.life,0,Math.PI*2);ctx.fillStyle=p.col;ctx.fill();}ctx.globalAlpha=1;}}if(!alive||ef>100)phase="done";}
    if(phase==="done"){cancelAnimationFrame(id);ctx.clearRect(0,0,W,H);return;}
    id=requestAnimationFrame(loop);
  }
  id=requestAnimationFrame(loop);
}

